import SwiftUI
import Combine

class ProductListViewModel: ObservableObject {
    @Published var products: [Product] = []
    @Published var isLoading = false
    @Published var errorMessage: String?
    @Published var searchText = ""

    private let apiService = APIService.shared
    private var cancellables = Set<AnyCancellable>()

    var filteredProducts: [Product] -> [Product] {
        guard !searchText.isEmpty else { return products }
        return products.filter { $0.name.localizedCaseInsensitiveContains(searchText) }
    }

    func loadProducts() {
        isLoading = true
        errorMessage = nil
        Task {
            do {
                let result = try await apiService.fetchProducts()
                await MainActor.run {
                    self.products = result
                    self.isLoading = false
                }
            } catch {
                await MainActor.run {
                    self.errorMessage = error.localizedDescription
                    self.isLoading = false
                }
            }
        }
    }

    func deleteProduct(_ product: Product) {
        Task {
            try? await apiService.delete(product.id)
            await MainActor.run {
                self.products.removeAll { $0.id == product.id }
            }
        }
    }
}

struct ProductListView: View {
    @StateObject var viewModel = ProductListViewModel()

    var body: some View {
        NavigationStack {
            List {
                ForEach(viewModel.filteredProducts) { product in
                    ProductRow(product: product)
                }
                .onDelete { indexSet in
                    for index in indexSet {
                        viewModel.deleteProduct(viewModel.filteredProducts[index])
                    }
                }
            }
            .searchable(text: $viewModel.searchText)
            .refreshable { viewModel.loadProducts() }
            .overlay {
                if viewModel.isLoading { ProgressView() }
            }
            .alert("Error", isPresented: .constant(viewModel.errorMessage != nil)) {
                Button("OK") { viewModel.errorMessage = nil }
            } message: {
                Text(viewModel.errorMessage ?? "")
            }
            .onAppear { viewModel.loadProducts() }
            .navigationTitle("Products")
        }
    }
}

struct Product: Identifiable, Equatable, Decodable {
    let id: UUID
    let name: String
    let price: Double
}
