Modernize this pre-1.0 TCA code to current TCA (1.7+). Keep all functionality:

```swift
struct TodosState: Equatable {
    var todos: [Todo] = []
    var isLoading = false
}

enum TodosAction: Equatable {
    case onAppear
    case todosLoaded(Result<[Todo], APIError>)
    case deleteTodo(IndexSet)
    case todoDeleted(Result<Bool, APIError>)
}

struct TodosEnvironment {
    var apiClient: APIClient
    var mainQueue: AnySchedulerOf<DispatchQueue>
}

let todosReducer = Reducer<TodosState, TodosAction, TodosEnvironment> { state, action, environment in
    switch action {
    case .onAppear:
        state.isLoading = true
        return environment.apiClient.fetchTodos()
            .receive(on: environment.mainQueue)
            .catchToEffect(TodosAction.todosLoaded)
    case .todosLoaded(.success(let todos)):
        state.isLoading = false
        state.todos = todos
        return .none
    case .todosLoaded(.failure):
        state.isLoading = false
        return .none
    case .deleteTodo(let indexSet):
        let id = state.todos[indexSet.first!].id
        state.todos.remove(atOffsets: indexSet)
        return environment.apiClient.deleteTodo(id)
            .receive(on: environment.mainQueue)
            .catchToEffect(TodosAction.todoDeleted)
    case .todoDeleted:
        return .none
    }
}

struct TodosView: View {
    let store: Store<TodosState, TodosAction>

    var body: some View {
        WithViewStore(store, observe: { $0 }) { viewStore in
            List {
                ForEach(viewStore.todos) { todo in
                    Text(todo.title)
                }
                .onDelete { viewStore.send(.deleteTodo($0)) }
            }
            .onAppear { viewStore.send(.onAppear) }
            .overlay {
                if viewStore.isLoading { ProgressView() }
            }
        }
    }
}
