Migrate this SwiftUI view and its ObservableObject to TCA with @ObservableState. The view uses @StateObject, @Published, Combine pipelines, and manual MainActor dispatching:

```swift
class TimerViewModel: ObservableObject {
    @Published var count = 0
    @Published var isRunning = false
    @Published var history: [Int] = []

    private var timer: AnyCancellable?

    func startTimer() {
        isRunning = true
        timer = Timer.publish(every: 1, on: .main, in: .common)
            .autoconnect()
            .sink { [weak self] _ in
                self?.count += 1
            }
    }

    func stopTimer() {
        timer?.cancel()
        timer = nil
        isRunning = false
    }

    func resetTimer() {
        stopTimer()
        history.append(count)
        count = 0
    }
}

struct TimerView: View {
    @StateObject private var viewModel = TimerViewModel()

    var body: some View {
        VStack(spacing: 20) {
            Text("\(viewModel.count)")
                .font(.system(size: 72, design: .monospaced))

            HStack {
                Button(viewModel.isRunning ? "Stop" : "Start") {
                    viewModel.isRunning ? viewModel.stopTimer() : viewModel.startTimer()
                }
                Button("Reset") { viewModel.resetTimer() }
                    .disabled(!viewModel.isRunning && viewModel.count == 0)
            }

            if !viewModel.history.isEmpty {
                Section("History") {
                    ForEach(viewModel.history.indices, id: \\.self) { i in
                        Text("Run \(i+1): \(viewModel.history[i])s")
                    }
                }
            }
        }
        .onDisappear { viewModel.stopTimer() }
    }
}
