case .searchQueryChanged(let query):
    state.searchQuery = query
    guard !query.isEmpty else {
        state.results = []
        return .cancel(id: SearchCancelID.self)
    }
    return Effect(value: .performSearch)
        .debounce(id: SearchCancelID.self, for: 0.3, scheduler: environment.mainQueue)

case .performSearch:
    return environment.searchClient.search(state.searchQuery)
        .receive(on: environment.mainQueue)
        .map(Action.searchResults)
        .catch { Just(.searchFailed($0)) }
        .eraseToEffect()

case .loadAndTransform:
    return Effect.concatenate(
        Effect(value: .setLoading(true)),
        environment.apiClient.fetch()
            .receive(on: environment.mainQueue)
            .map(Action.dataLoaded)
            .catch { Just(.loadFailed($0)) }
            .eraseToEffect(),
        Effect(value: .setLoading(false))
    )

case .fireAnalytics:
    return Effect.fireAndForget {
        environment.analytics.track("page_viewed")
    }

struct SearchCancelID: Hashable {}
