Extract the settings logic from this god reducer into a separate SettingsFeature child. The settings section handles theme, notifications, and logout with an alert. Keep the parent AppFeature composing it:

```swift
@Reducer
struct AppFeature {
    @ObservableState
    struct State: Equatable {
        // Tab state
        var selectedTab: Tab = .home
        var homeItems: [Item] = []

        // Settings state (extract this)
        var isDarkMode = false
        var notificationsEnabled = true
        var showLogoutAlert = false
        var settingsIsLoading = false

        enum Tab { case home, settings }
    }

    enum Action {
        // Home actions
        case selectTab(State.Tab)
        case homeItemsLoaded([Item])

        // Settings actions (extract these)
        case toggleDarkMode
        case toggleNotifications
        case logoutTapped
        case logoutConfirmed
        case logoutCancelled
        case settingsSaved(Result<Void, Error>)
    }

    @Dependency(\.apiClient) var apiClient
    @Dependency(\.userDefaults) var userDefaults

    var body: some ReducerOf<Self> {
        Reduce { state, action in
            switch action {
            case .selectTab(let tab):
                state.selectedTab = tab
                return .none
            case .homeItemsLoaded(let items):
                state.homeItems = items
                return .none
            case .toggleDarkMode:
                state.isDarkMode.toggle()
                return .run { [isDark = state.isDarkMode] _ in
                    await userDefaults.set(isDark, forKey: "darkMode")
                }
            case .toggleNotifications:
                state.notificationsEnabled.toggle()
                return .run { [enabled = state.notificationsEnabled] send in
                    try await apiClient.updateNotificationSettings(enabled)
                    await send(.settingsSaved(.success(())))
                } catch: { error, send in
                    await send(.settingsSaved(.failure(error)))
                }
            case .logoutTapped:
                state.showLogoutAlert = true
                return .none
            case .logoutConfirmed:
                state.showLogoutAlert = false
                state.settingsIsLoading = true
                return .run { send in
                    try await apiClient.logout()
                    // Reset everything
                }
            case .logoutCancelled:
                state.showLogoutAlert = false
                return .none
            case .settingsSaved(.success):
                return .none
            case .settingsSaved(.failure):
                state.notificationsEnabled.toggle() // Revert
                return .none
            }
        }
    }
}
```
